import React from 'react';
import './world-map.css'
import westmeath from './louth.json'
import louth from './louth.json'; // Import the louth map data

class Overworld extends React.Component {
  constructor(props) {
    super(props);

    this.state = {
      currentMap: westmeath.mapData, // Initial map data
    };
  }

  handleMapChange = () => {
    // Toggle between maps when the button is clicked
    this.setState((prevState) => ({
      currentMap: prevState.currentMap === westmeath.mapData ? louth.mapData : westmeath.mapData,
    }));
  };

  render() {
    const { currentMap } = this.state;

    return (
      <div className="world-map-container">
        <button onClick={this.handleMapChange}>Toggle Map</button>
        <div className="world-map">
          {currentMap.map((row, rowIndex) => (
            <div key={`row-${rowIndex}`} className="map-row">
              {row.map((tile, colIndex) => (
                <div key={`col-${colIndex}`} className={`map-tile tile-${tile}`}>
                  {tile}
                </div>
              ))}
            </div>
          ))}
        </div>
      </div>
    );
  }
}

export default Overworld;
